$a->strings['✅ What RealMember can do'] = '✅ Das kann RealMember';
$a->strings['<strong>Risk assessment of all users:</strong> Every registered account is automatically analyzed based on multiple criteria and receives a risk score from 0% to 100%.'] = '<strong>Risiko-Bewertung aller Nutzer:</strong> Jedes registrierte Konto wird automatisch auf verschiedene Kriterien analysiert und erhält einen Risiko-Score von 0 % bis 100 %.';
$a->strings['<strong>Disposable email detection:</strong> Email addresses are checked against a community-maintained list of thousands of known disposable providers.'] = '<strong>Wegwerf-E-Mail-Erkennung:</strong> E-Mail-Adressen werden gegen eine von der Community gepflegte Liste mit tausenden bekannten Trashmail-Anbietern geprüft.';
$a->strings['<strong>Detect suspicious domains:</strong> Domain extensions (TLDs) commonly abused for spam are automatically detected.'] = '<strong>Verdächtige Domains erkennen:</strong> Domain-Endungen (TLDs), die überproportional häufig für Spam missbraucht werden, werden automatisch erkannt.';
$a->strings['<strong>Keyword scan:</strong> Usernames and registration notes are searched for almost 200 suspicious terms from the fields of pharma, crypto, erotics, and marketing.'] = '<strong>Keyword-Scan:</strong> Nutzernamen und Registrierungs-Notizen werden nach fast 200 verdächtigen Begriffen aus den Bereichen Pharma, Krypto, Erotik und Marketing durchsucht.';
$a->strings['<strong>Bot detection (entropy):</strong> Randomly generated nicknames and email prefixes without natural word structure are detected using pattern analysis.'] = '<strong>Bot-Erkennung (Entropie):</strong> Zufällig generierte Nicknames und E-Mail-Präfixe ohne natürliche Wortstruktur werden durch eine Muster-Analyse erkannt.';
$a->strings['<strong>Include admin rules:</strong> Your own email blocklists from Friendica settings are automatically included in the assessment.'] = '<strong>Admin-Regeln einbeziehen:</strong> Deine eigenen E-Mail-Sperrlisten aus den Friendica-Einstellungen werden automatisch in die Bewertung einbezogen.';
$a->strings['<strong>Filtering & Sorting:</strong> You can filter and sort results by time period, suspected spam, name, email, or risk score.'] = '<strong>Filtern & Sortieren:</strong> Ergebnisse lassen sich nach Zeitraum, Spamverdacht, Name, E-Mail oder Risiko-Score filtern und sortieren.';
$a->strings['<strong>Search:</strong> A full-text search across names, handles, and email addresses is integrated.'] = '<strong>Suche:</strong> Eine Volltextsuche über Namen, Handles und E-Mail-Adressen ist integriert.';
$a->strings['<strong>Automatic updates:</strong> The disposable domain list can be automatically updated daily via a cron job.'] = '<strong>Automatische Updates:</strong> Die Trashmail-Domainliste kann per Cronjob täglich vollautomatisch aktualisiert werden.';
$a->strings['<strong>Seamless integration:</strong> RealMember appears as a tab in Friendica moderation and blends seamlessly into the existing interface.'] = '<strong>Nahtlose Integration:</strong> RealMember erscheint als Tab in der Friendica-Moderation und fügt sich nahtlos in die bestehende Oberfläche ein.';
$a->strings['🔒 Security Guarantee'] = '🔒 Sicherheitsgarantie';
$a->strings['<strong>Read-only:</strong> RealMember exclusively reads data. No database entries are created, modified, or deleted.'] = '<strong>Rein lesend:</strong> RealMember liest ausschließlich Daten. Es werden keine Datenbank-Einträge erstellt, verändert oder gelöscht.';
$a->strings['<strong>No automated actions:</strong> RealMember never blocks, deletes, or modifies any account automatically. All decisions are made by the admin.'] = '<strong>Keine automatischen Aktionen:</strong> RealMember blockiert, löscht oder verändert niemals selbstständig Konten. Alle Entscheidungen trifft der Admin.';
$a->strings['<strong>Only for admins:</strong> The dashboard is only visible to site administrators.'] = '<strong>Nur für Admins:</strong> Das Dashboard ist ausschließlich für Administratoren der Instanz sichtbar.';
$a->strings['⚠️ What RealMember cannot do'] = '⚠️ Das kann RealMember nicht';
$a->strings['<strong>No guarantee:</strong> RealMember is an assistance system. Not every flagged account is actually spam, and not every spammer will be detected.'] = '<strong>Keine Garantie:</strong> RealMember ist ein Assistenzsystem. Nicht jedes markierte Konto ist tatsächlich Spam, und nicht jeder Spammer wird erkannt.';
$a->strings['<strong>No content scan:</strong> Published posts, comments, or messages of users are not analyzed.'] = '<strong>Kein Inhalts-Scan:</strong> Veröffentlichte Beiträge, Kommentare oder Nachrichten von Nutzern werden nicht analysiert.';
$a->strings['<strong>No real-time monitoring:</strong> The analysis runs on every page load. There are no push notifications for new suspected spam cases.'] = '<strong>Keine Echtzeit-Überwachung:</strong> Die Analyse läuft bei jedem Seitenaufruf. Es gibt keine Push-Benachrichtigungen bei neuen Spamverdachtsfällen.';
$a->strings['<strong>No deletion or blocking:</strong> RealMember cannot block or delete accounts. Use Friendica\'s moderation area for this.'] = '<strong>Kein Löschen oder Sperren:</strong> RealMember kann keine Konten sperren oder löschen. Nutze dafür den Friendica-Moderationsbereich.';
